389	    const pendingCommands = {};
390	
391	    function ago(seconds) {
392	      if (seconds === null || seconds === undefined) return "unknown";
393	      if (seconds < 5)  return "just now";
394	      if (seconds < 60) return seconds + "s ago";
395	      if (seconds < 3600) return Math.floor(seconds / 60) + "m ago";
396	      return Math.floor(seconds / 3600) + "h ago";
397	    }
398	
399	    function fmtFiles(n) {
400	      if (n === null || n === undefined) return "—";
401	      return n.toLocaleString();
402	    }
403	
404	    function fmtRate(kb) {
405	      if (kb === null || kb === undefined || Number.isNaN(Number(kb))) return "—";
406	      const val = Number(kb);
407	      if (val >= 1024) return (val / 1024).toFixed(1) + " MB/s";
408	      return val.toFixed(1) + " KB/s";
409	    }
