423	
424	    function badgeClass(entry, state, stale) {
425	      if (stale) return "idle";
426	      const verify = entry.verification || {};
427	      if (verify.status === "anomaly") return "error";
428	      if (entry.paused) return "paused";
429	      if (state === "synchronized" && verify.status === "healthy") return "verified";
430	      if (state === "synchronized") return "ok";
431	      if (state === "uploading" || state === "downloading") return "busy";
432	      if (state === "error") return "error";
433	      return "idle";
434	    }
