436	    function badgeLabel(entry, state, stale) {
437	      if (stale) return "Offline";
438	      if (!entry.daemon_alive) return "Daemon stopped";
439	      const verify = entry.verification || {};
440	      if (verify.status === "anomaly") return "Sync anomaly";
441	      if (entry.paused) return "Paused";
442	      if (state === "synchronized" && verify.status === "healthy") return "Verified synchronized";
443	      if (state === "synchronized") return "Synchronized (unverified)";
444	      if (state === "uploading") {
445	        const pct = entry.repos[0]?.progress_pct;
446	        const rate = entry.repos[0]?.rate_kb;
447	        let label = "Uploading";
448	        if (pct !== null && pct !== undefined) label += " " + pct + "%";
449	        if (rate !== null && rate !== undefined && rate > 0) label += " · " + fmtRate(rate);
