459	    async function sendCommand(libraryUuid, verb, btn) {
460	      btn.disabled = true;
461	      const label = verb === "resume" ? "Resume" : "Pause";
462	      pendingCommands[libraryUuid] =
463	        `${label} requested. Waiting for the next seaf-cli heartbeat to confirm the actual state.`;
464	      try {
465	        const resp = await fetch("{{ url_for('api_command') }}", {
466	          method: "POST",
467	          headers: {"Content-Type": "application/json"},
468	          body: JSON.stringify({library_uuid: libraryUuid, verb}),
469	        });
470	        if (!resp.ok) throw new Error("server error");
471	      } catch (e) {
472	        pendingCommands[libraryUuid] = null;
473	        alert("Failed to send command. Try again.");
474	      } finally {
475	        btn.disabled = false;
476	        refresh();
477	      }
478	    }
479	
480	    function escapeHtml(value) {
481	      return String(value).replace(/[&<>"']/g, ch => ({
482	        "&": "&amp;",
483	        "<": "&lt;",
484	        ">": "&gt;",
485	        '"': "&quot;",
486	        "'": "&#39;",
487	      })[ch]);
488	    }
