490	    function commandNote(lib, data) {
491	      const pending = pendingCommands[lib.uuid];
492	
493	      if (data && !data.stale && data.schedule_note) {
494	        pendingCommands[lib.uuid] = null;
495	        return `<div class="command-note warn">${escapeHtml(data.schedule_note)}</div>`;
496	      }
497	
498	      if (pending) {
499	        return `<div class="command-note info">${escapeHtml(pending)}</div>`;
500	      }
501	
502	      return "";
503	    }
504	
505	    function renderVerification(data) {
506	      const verify = data.verification;
507	      if (!verify) return "";
508	      const bad = verify.status === "anomaly";
509	      const daemon = verify.daemon_health || data.daemon_health || {};
510	      const ino = daemon.inotify || {};
511	      const log = daemon.log || {};
512	      const canary = verify.canary || {};
513	      const grid = `<div class="transfer-grid">
514	            <div><label>Client head</label><div class="val">${verify.client_head ? escapeHtml(verify.client_head.slice(0, 12)) : "—"}</div></div>
515	            <div><label>Server head</label><div class="val">${verify.server_head ? escapeHtml(verify.server_head.slice(0, 12)) : "—"}</div></div>
516	            <div><label>Checked</label><div class="val">${verify.checked_at ? new Date(verify.checked_at).toLocaleTimeString() : "—"}</div></div>
517	            <div><label>Canary</label><div class="val">${canary.ok === true ? "OK" : canary.ok === false ? "Failed" : "Unknown"}</div></div>
518	            <div><label>Watch limit</label><div class="val">${ino.max_user_watches ?? "—"}</div></div>
519	            <div><label>Watches used</label><div class="val">${ino.watches_in_use ?? "—"}</div></div>
520	            <div><label>Watch errors</label><div class="val">${log.new_watch_errors ?? "—"}</div></div>
521	            <div><label>Alert</label><div class="val">${verify.alert?.sent ? "Sent" : verify.alert?.reason ? escapeHtml(verify.alert.reason) : "—"}</div></div>
522	          </div>`;
523	      const parts = [];
524	      if (daemon.issues?.length) parts.push(daemon.issues.map(escapeHtml).join("<br>"));
525	      if (verify.diagnostics?.head_check) parts.push(escapeHtml(verify.diagnostics.head_check));
526	      return `<div class="verify-panel ${bad ? "bad" : ""}">
527	        <div class="verify-title">Independent verification: ${escapeHtml(verify.status || "unknown")}</div>
528	        ${grid}
529	        ${verify.reason ? `<div class="diff-list">${escapeHtml(verify.reason)}</div>` : ""}
530	        ${parts.length ? `<div class="diff-list">${parts.join("<br>")}</div>` : ""}
531	      </div>`;
532	    }
533	
534	    function renderCard(lib, data) {
535	      const bodyEl   = document.getElementById("body-" + lib.id);
